  if (TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN && TWILIO_FROM && TWILIO_TO) {
    tasks.push(
      sendWhatsApp(`${title}: ${description}`)
        .catch(e => logger.warn(`WhatsApp notify failed: ${e.message}`))
