12	// Returns null if blank, equal start/end (disabled), or unparseable (warn + disable).
13	function parseQuietHours(raw) {
14	  if (!raw || !raw.trim()) return null;
15	  const m = raw.trim().match(/^(\d{1,2}):(\d{2})-(\d{1,2}):(\d{2})$/);
16	  if (!m) {
