18	    return null;
19	  }
20	  const startMins = parseInt(m[1], 10) * 60 + parseInt(m[2], 10);
21	  const endMins   = parseInt(m[3], 10) * 60 + parseInt(m[4], 10);
22	  if (startMins === endMins) return null;
23	  return { startMins, endMins };
