1	'use strict';
2	
3	// Interactive Discord auth flow using a proper bot token (discord.js WebSocket).
4	// This is separate from the existing DISCORD_WEBHOOK_URL one-way notifications.
5	//
6	// When enabled, auth failures post a message with buttons so the user can
7	// authorize Claude from Discord or approve API key fallback, without SSH-ing in.
8	
9	const logger = require('./logger');
10	
11	const INTERACTIVE_AUTH   = (process.env.DISCORD_INTERACTIVE_AUTH || '').toLowerCase() === 'true';
12	const BOT_TOKEN          = process.env.DISCORD_BOT_TOKEN  || '';
13	const CHANNEL_ID         = process.env.DISCORD_CHANNEL_ID || '';
14	const TIMEOUT_MINUTES        = parseInt(process.env.DISCORD_AUTH_TIMEOUT_MINUTES || '5', 10);
15	const TIMEOUT_MS             = TIMEOUT_MINUTES * 60 * 1000;
16	const RATE_LIMIT_TIMEOUT_MS  = 24 * 60 * 60 * 1000;
17	
18	let client  = null;
19	let pendingDecision = null;  // { resolve, timeoutId, messageRef }
20	let expediteHandler = null;  // registered by index.js via setExpediteHandler
21	
22	function isEnabled() {
23	  return INTERACTIVE_AUTH && !!client;
24	}
25	
26	// Registers the callback invoked when the user clicks an Expedite button.
27	// Wired in index.js to avoid a circular dependency between discord-bot and inbox-watcher.
28	function setExpediteHandler(fn) {
29	  expediteHandler = fn;
30	}
31	
32	// Call once at startup when DISCORD_INTERACTIVE_AUTH=true.
33	// Returns a promise that resolves once the bot is ready (or rejects on bad token).
34	async function init() {
35	  if (!INTERACTIVE_AUTH) return;
36	  if (!BOT_TOKEN)   throw new Error('DISCORD_INTERACTIVE_AUTH=true but DISCORD_BOT_TOKEN is not set');
37	  if (!CHANNEL_ID)  throw new Error('DISCORD_INTERACTIVE_AUTH=true but DISCORD_CHANNEL_ID is not set');
38	
39	  // Lazy-require discord.js so non-interactive mode has zero overhead.
40	  const { Client, GatewayIntentBits } = require('discord.js');
41	
42	  client = new Client({
43	    intents: [
44	      GatewayIntentBits.Guilds,
45	      GatewayIntentBits.GuildMessages,
46	      GatewayIntentBits.MessageContent,
47	    ],
48	  });
49	
50	  client.on('interactionCreate', async (interaction) => {
51	    if (!interaction.isButton()) return;
52	
53	    // ---- Per-item expedite (fire-and-forget, no pendingDecision involved) ----
54	    if (interaction.customId.startsWith('research_expedite:')) {
55	      const filename = interaction.customId.slice('research_expedite:'.length);
56	      await interaction.deferUpdate().catch(() => {});
57	      if (expediteHandler) {
58	        try {
59	          await expediteHandler(filename);
60	          const displayName = filename.replace(/\.md$/, '').replace(/-/g, ' ');
61	          await interaction.editReply({ content: `▶️ Expediting *${displayName}*…`, components: [] }).catch(() => {});
62	        } catch (err) {
63	          logger.warn(`discord-bot: expedite handler failed (${err.message})`);
64	          await interaction.editReply({ content: '⚠️ Expedite failed — check bot logs.', components: [] }).catch(() => {});
65	        }
66	      } else {
67	        await interaction.editReply({ content: '⚠️ Expedite handler not registered.', components: [] }).catch(() => {});
68	      }
69	      return;
70	    }
71	
72	    // ---- Auth / rate-limit decisions (block until user acts) -----------------
73	    if (!pendingDecision) {
74	      await interaction.reply({ content: 'No pending auth decision.', ephemeral: true }).catch(() => {});
75	      return;
76	    }
77	
78	    const { resolve, timeoutId, messageRef } = pendingDecision;
79	    pendingDecision = null;
80	    clearTimeout(timeoutId);
81	
82	    const id = interaction.customId;
83	    let responseText;
84	
85	    if (id === 'auth-done') {
86	      responseText = '✅ Got it — retrying with subscription…';
87	      await safeUpdate(interaction, responseText, []);
88	      resolve('retry-subscription');
89	    } else if (id === 'auth-api-key') {
90	      responseText = '💰 Using API key for this task.';
91	      await safeUpdate(interaction, responseText, []);
92	      resolve('use-api-key');
93	    } else if (id === 'rate-limit-wait') {
94	      responseText = '⏳ Holding until rate limit resets.';
95	      await safeUpdate(interaction, responseText, []);
96	      resolve('wait-for-reset');
97	    } else if (id === 'rate-limit-api-key') {
98	      responseText = '💰 Using API key for this task.';
99	      await safeUpdate(interaction, responseText, []);
100	      resolve('use-api-key');
101	    } else {
102	      // Unknown button — ignore
103	      await interaction.reply({ content: 'Unknown action.', ephemeral: true }).catch(() => {});
104	      // Put it back
105	      pendingDecision = { resolve, timeoutId, messageRef };
106	    }
107	  });
108	
109	  // ---- Text commands (!research hold / release / status) -------------------
110	  // Requires "Message Content Intent" in the Discord developer portal.
111	  client.on('messageCreate', async (message) => {
112	    if (message.author.bot) return;
113	    if (message.channelId !== CHANNEL_ID) return;
114	    const text = message.content.trim().toLowerCase();
115	    if      (text === '!research hold')    await handleHoldCommand(message, true);
116	    else if (text === '!research release') await handleHoldCommand(message, false);
117	    else if (text === '!research status')  await handleStatusCommand(message);
118	  });
119	
120	  // Wait for the `ready` event — login() only resolves when the auth request
121	  // is sent, not when the gateway handshake completes. Calling channel.send()
122	  // before ready causes silent failures.
123	  await new Promise((resolve, reject) => {
124	    client.once('ready', resolve);
125	    client.login(BOT_TOKEN).catch(reject);
126	  });
127	
128	  logger.info('discord-bot: ready');
129	}
130	
131	async function handleHoldCommand(message, activate) {
132	  const researchGate = require('./research-gate');
133	  try {
134	    if (activate && researchGate.isHoldActive()) {
135	      await message.reply('Research is already on hold.').catch(() => {});
136	      return;
137	    }
138	    if (!activate && !researchGate.isHoldActive()) {
139	      await message.reply('Research is not currently on hold.').catch(() => {});
140	      return;
141	    }
142	    await researchGate.setHold(activate);
143	    const reply = activate
144	      ? 'Research processing paused. Use `!research release` to resume.'
145	      : 'Research processing resumed.';
146	    await message.reply(reply).catch(() => {});
147	    logger.info(`discord-bot: research hold ${activate ? 'activated' : 'released'} via Discord`);
148	  } catch (err) {
149	    logger.warn(`discord-bot: hold command failed (${err.message})`);
150	    await message.reply('Failed to update hold state — check bot logs.').catch(() => {});
151	  }
152	}
153	
154	async function handleStatusCommand(message) {
155	  const researchGate = require('./research-gate');
156	  const holdActive = researchGate.isHoldActive();
157	  const gateReason = researchGate.researchGateReason();
158	  const holdLine   = holdActive ? '🔴 Hold: **active**' : '🟢 Hold: inactive';
159	  const gateLine   = gateReason ? `Gate: \`${gateReason}\`` : 'Gate: clear';
160	  await message.reply(`${holdLine}\n${gateLine}`).catch(() => {});
161	}
162	
163	// Posts an auth decision message to DISCORD_CHANNEL_ID and waits for the user
164	// to click a button or for the timeout to expire.
165	// Returns: 'retry-subscription' | 'use-api-key'
166	// Never rejects — errors fall back to 'use-api-key'.
167	async function askAuthDecision(label, oauthUrl, loginProc) {
168	  if (!client) return 'use-api-key';
169	
170	  try {
171	    const { ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
172	    const channel = await client.channels.fetch(CHANNEL_ID);
173	
174	    const row = new ActionRowBuilder().addComponents(
175	      new ButtonBuilder()
176	        .setLabel('🔐 Authorize Claude')
177	        .setStyle(ButtonStyle.Link)
178	        .setURL(oauthUrl),
179	      new ButtonBuilder()
180	        .setCustomId('auth-done')
181	        .setLabel('✅ Done — retry subscription')
182	        .setStyle(ButtonStyle.Success),
183	      new ButtonBuilder()
184	        .setCustomId('auth-api-key')
185	        .setLabel('💰 Use API Key')
186	        .setStyle(ButtonStyle.Danger),
187	    );
188	
189	    const taskLine = label ? `\n**Task:** *${label}*` : '';
190	    const content = [
191	      `⚠️ **rockybot: Claude subscription auth expired**${taskLine}`,
192	      `Click **Authorize Claude** to re-auth, then **Done** when finished.`,
193	      `Or use the API key (charges apply). Auto-fallback in **${TIMEOUT_MINUTES} min**.`,
194	    ].join('\n');
195	
196	    const msg = await channel.send({ content, components: [row] });
197	
198	    return await new Promise((resolve) => {
199	      const timeoutId = setTimeout(async () => {
200	        if (!pendingDecision) return;
